import{_ as e,o as n,c as t,a5 as i}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"概念：Vienna PFC 与中点电压平衡","description":"","frontmatter":{"date":"2026-06-22T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：Vienna PFC 与中点电压平衡","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0041-vienna-pfc-neutral-point-balance.html` 的源稿。"},"headers":[],"relativePath":"content/power/concepts/vienna-pfc-neutral-point-balance.md","filePath":"content/power/concepts/vienna-pfc-neutral-point-balance.md","lastUpdated":1782835746000}'),o={name:"content/power/concepts/vienna-pfc-neutral-point-balance.md"};function s(l,a,c,r,p,d){return n(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="概念-vienna-pfc-与中点电压平衡" tabindex="-1">概念：Vienna PFC 与中点电压平衡 <a class="header-anchor" href="#概念-vienna-pfc-与中点电压平衡" aria-label="Permalink to &quot;概念：Vienna PFC 与中点电压平衡&quot;">​</a></h1><p>本页是 <code>lessons/0041-vienna-pfc-neutral-point-balance.html</code> 的源稿。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>维也纳整流器（Vienna rectifier）是三相三电平单向 PFC 整流拓扑。中点电压平衡（neutral-point voltage balance）要求上下母线电容电压接近相等。</p><h2 id="为什么-ups-pcs-需要它" tabindex="-1">为什么 UPS/PCS 需要它 <a class="header-anchor" href="#为什么-ups-pcs-需要它" aria-label="Permalink to &quot;为什么 UPS/PCS 需要它&quot;">​</a></h2><p>中大功率三相 UPS 前级常需要高效率和低输入谐波。Vienna PFC 可降低器件应力，但必须管理分裂母线。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Vdc = Vc_top + Vc_bottom</span></span>
<span class="line"><span>Vnp_err = Vc_top - Vc_bottom</span></span>
<span class="line"><span>id_ref = PI(Vdc_ref - Vdc)</span></span>
<span class="line"><span>iq_ref = 0</span></span></code></pre></div><h2 id="一个仿真任务" tabindex="-1">一个仿真任务 <a class="header-anchor" href="#一个仿真任务" aria-label="Permalink to &quot;一个仿真任务&quot;">​</a></h2><p>人为设置上下电容电压不等，观察加入平衡项后 <code>Vnp_err</code> 收敛。</p><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能解释 Vienna 和三相 Boost PFC 的区别。</li><li>能说明为什么总母线电压正常不代表中点平衡。</li><li>能区分 Vdc 环、id/iq 环和中点平衡环。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><p>中点平衡逻辑在真实代码中通常放在调制层还是控制层？</p>`,14)])])}const _=e(o,[["render",s]]);export{u as __pageData,_ as default};
